import re

def norm_doc(d):
    return re.sub(r'[^a-z0-9]', '', str(d).casefold())

def blocking_key(rec):
    return f"{str(rec.get('surname','')).casefold()}|{str(rec.get('city','')).casefold()}"

def er_score(a, b):
    same_doc = norm_doc(a.get('doc')) == norm_doc(b.get('doc')) and norm_doc(a.get('doc')) != ''
    same_block = blocking_key(a) == blocking_key(b)
    if same_doc and same_block:
        return 1.0
    if same_doc or same_block:
        return 0.5
    return 0.0

a = {'doc': 'D-1', 'surname': 'q', 'city': 'lima'}
b = {'doc': 'D1', 'surname': 'q', 'city': 'lima'}
c = {'doc': 'D-1', 'surname': 'x', 'city': 'cusco'}
d = {'doc': 'Z', 'surname': 'y', 'city': 'arequipa'}
print(er_score(a,b), er_score(a,c), er_score(a,d))

def rel_score(km, surname_jaccard):
    geo = 1.0 if km is not None and km <= 2.0 else 0.0
    return round(0.8 * geo + 0.2 * float(surname_jaccard), 1)

print(f"{rel_score(1.0, 1.0)} y {rel_score(5.0, 1.0)}")

