from math import isfinite

th = {"accept_min": 0.8, "review_low": 0.4}

def decide_ops_status(score, unc, th):
    try:
        s = float(score)
    except (TypeError, ValueError):
        return 'invalid_input'
    if (not isfinite(s)) or s < 0 or s > 1 or unc not in {'low', 'med', 'high'}:
        return 'invalid_input'
    if unc == 'high':
        return 'needs_review'
    if s < th['review_low']:
        return 'abstain'
    if s < th['accept_min']:
        return 'needs_review'
    return 'accept_pair'

cases = [(-0.1, 'low'), (0.399, 'low'), (0.4, 'low'), (0.799, 'low'), (0.8, 'low'), (1.0, 'low'), (0.9, 'high'), (float('nan'), 'low'), (0.5, '?')]
for s, u in cases:
    print(s, u, decide_ops_status(s, u, th))

